def apply():
    updated = 0
    for fp in sorted(glob.glob(os.path.join(CALC_DIR, "*.json"))):
        if "bak" in fp or "monolithic" in fp or os.path.basename(fp) == "calculators.json": continue
        with open(fp, "r", encoding="utf-8-sig") as f: calc = json.load(f)
        cid = calc.get("id", "")
        if cid not in fixes: continue
        en = calc.setdefault("i18n", {}).setdefault("en", {})
        changed = False
        for k, v in fixes[cid].items():
            if k in en and en[k] == v: continue
            en[k] = v
            changed = True
        if changed:
            with open(fp, "w", encoding="utf-8", newline="\n") as f:
                json.dump(calc, f, ensure_ascii=False, indent=2)
            updated += 1
    print(f"Updated {updated}")

apply()
